class Provider {
  constructor() {
    this.baseUrl = "https://mangaflix.net";
    this.apiUrl = "https://api.mangaflix.net/v1";
    this.lang = "pt-BR";
  }

  async requestJson(url) {
    const res = await fetch(url, {
      headers: {
        Accept: "application/json, text/plain, */*",
      },
    });

    if (!res.ok) {
      throw new Error(`HTTP ${res.status} while requesting ${url}`);
    }

    return await res.json();
  }

  normalizeText(value) {
    return typeof value === "string" ? value.trim() : "";
  }

  toArray(value) {
    return Array.isArray(value) ? value : [];
  }

  uniqueStrings(values) {
    const seen = {};
    const out = [];

    for (let i = 0; i < values.length; i++) {
      const value = this.normalizeText(values[i]);
      const key = value.toLowerCase();
      if (!value || seen[key]) continue;
      seen[key] = true;
      out.push(value);
    }

    return out;
  }

  parseYear(value) {
    if (!value) return undefined;
    const match = String(value).match(/\b(19|20)\d{2}\b/);
    return match ? Number(match[0]) : undefined;
  }

  chapterNumberValue(chapter) {
    const raw = chapter && chapter.number != null ? String(chapter.number).trim() : "";
    const parsed = parseFloat(raw.replace(",", "."));
    return isNaN(parsed) ? Number.MAX_SAFE_INTEGER : parsed;
  }

  mangaToSearchResult(item) {
    const title = this.normalizeText(item && item.name) || "Sem título";
    const synonyms = this.uniqueStrings(
      []
        .concat(this.toArray(item && item.alternativeNames))
        .concat(this.toArray(item && item.aliases))
        .concat(this.toArray(item && item.synonyms))
        .concat(this.toArray(item && item.altTitles))
    );

    const year =
      this.parseYear(item && item.year) ||
      this.parseYear(item && item.release_year) ||
      this.parseYear(item && item.createdAt);

    return {
      id: item && item._id ? String(item._id) : "",
      title: title,
      synonyms: synonyms,
      year: year,
      image: item && item.poster ? item.poster.default_url : undefined,
    };
  }

  chapterToDetails(chapter, index) {
    const chapterId = chapter && chapter._id ? String(chapter._id) : "";
    const rawNumber = chapter && chapter.number != null ? String(chapter.number).trim() : "";
    const explicitName = this.normalizeText(chapter && chapter.name);
    const title = explicitName || (rawNumber ? `Capítulo ${rawNumber}` : `Capítulo ${index + 1}`);

    const scanlator = this.uniqueStrings(
      this.toArray(chapter && chapter.owners).map((owner) => owner && owner.name)
    ).join(", ");

    return {
      id: chapterId,
      url: `${this.baseUrl}/br/manga/${chapterId}`,
      title: title,
      chapter: rawNumber || String(index + 1),
      index: index,
      scanlator: scanlator || undefined,
      language: this.lang,
      updatedAt: chapter && chapter.iso_date ? chapter.iso_date : undefined,
    };
  }

  dedupeChapters(chapters) {
    const seen = {};
    const out = [];

    for (let i = 0; i < chapters.length; i++) {
      const chapter = chapters[i];
      const key = [
        chapter && chapter._id ? String(chapter._id) : "",
        chapter && chapter.number != null ? String(chapter.number).trim() : "",
        this.normalizeText(chapter && chapter.name).toLowerCase(),
      ].join("|");

      if (seen[key]) continue;
      seen[key] = true;
      out.push(chapter);
    }

    return out;
  }

  scoreSearchItem(item, query, expectedYear) {
    const normalizedQuery = this.normalizeText(query).toLowerCase();
    const compactQuery = normalizedQuery.replace(/[^a-z0-9]+/g, "");
    const title = this.normalizeText(item && item.title).toLowerCase();
    const synonyms = this.toArray(item && item.synonyms).map((s) => this.normalizeText(s).toLowerCase());
    const allNames = [title].concat(synonyms).filter(Boolean);

    let score = 0;

    for (let i = 0; i < allNames.length; i++) {
      const name = allNames[i];
      const compactName = name.replace(/[^a-z0-9]+/g, "");

      if (name === normalizedQuery) score += 250;
      else if (compactName && compactName === compactQuery) score += 220;
      else if (name.indexOf(normalizedQuery) !== -1) score += 100;
      else if (normalizedQuery.indexOf(name) !== -1) score += 60;
      else if (compactName && compactQuery && compactName.indexOf(compactQuery) !== -1) score += 40;
    }

    if (expectedYear && item && item.year) {
      if (Number(item.year) === Number(expectedYear)) score += 30;
      else if (Math.abs(Number(item.year) - Number(expectedYear)) === 1) score += 10;
    }

    if (item && item.image) score += 5;

    return score;
  }

  sortSearchResults(items, query, expectedYear) {
    return items.slice().sort((a, b) => {
      const scoreA = this.scoreSearchItem(a, query, expectedYear);
      const scoreB = this.scoreSearchItem(b, query, expectedYear);
      if (scoreA !== scoreB) return scoreB - scoreA;

      const yearA = a && a.year ? Number(a.year) : 0;
      const yearB = b && b.year ? Number(b.year) : 0;
      if (yearA !== yearB) return yearB - yearA;

      return String(a.title || "").localeCompare(String(b.title || ""));
    });
  }

  async fallbackSearch(query) {
    const url = `${this.apiUrl}/latest-releases?selected_language=pt-br`;
    const json = await this.requestJson(url);
    const data = this.toArray(json && json.data);
    const loweredQuery = this.normalizeText(query).toLowerCase();

    return data
      .filter((item) => {
        const title = this.normalizeText(item && item.name).toLowerCase();
        return item && item._id && title && title.indexOf(loweredQuery) !== -1;
      })
      .map((item) => this.mangaToSearchResult(item));
  }

  async search(opts) {
    const query = this.normalizeText(opts && opts.query);
    const expectedYear = opts && opts.year ? Number(opts.year) : undefined;
    if (!query) return [];

    const url = `${this.apiUrl}/search/mangas?query=${encodeURIComponent(query)}&selected_language=pt-br`;
    const json = await this.requestJson(url);
    const data = json && json.data ? json.data : {};
    const works = this.toArray(data.works);

    let results = works
      .filter((item) => item && item._id && this.normalizeText(item.name))
      .map((item) => this.mangaToSearchResult(item));

    if (!results.length) {
      results = await this.fallbackSearch(query);
    }

    const deduped = [];
    const seen = {};

    for (let i = 0; i < results.length; i++) {
      const item = results[i];
      const key = String(item.id || "");
      if (!key || seen[key]) continue;
      seen[key] = true;
      deduped.push(item);
    }

    return this.sortSearchResults(deduped, query, expectedYear);
  }

  async findChapters(id) {
    const mangaId = this.normalizeText(id);
    if (!mangaId) return [];

    const url = `${this.apiUrl}/mangas/${encodeURIComponent(mangaId)}`;
    const json = await this.requestJson(url);
    const data = json && json.data ? json.data : {};
    const rawChapters = this.toArray(data.chapters);

    const chapters = this.dedupeChapters(rawChapters).sort((a, b) => {
      const numberA = this.chapterNumberValue(a);
      const numberB = this.chapterNumberValue(b);
      if (numberA !== numberB) return numberA - numberB;

      const dateA = new Date(a && a.iso_date ? a.iso_date : 0).getTime();
      const dateB = new Date(b && b.iso_date ? b.iso_date : 0).getTime();
      return dateA - dateB;
    });

    return chapters
      .filter((chapter) => chapter && chapter._id)
      .map((chapter, index) => this.chapterToDetails(chapter, index));
  }

  async findChapterPages(id) {
    const chapterId = this.normalizeText(id);
    if (!chapterId) return [];

    const url = `${this.apiUrl}/chapters/${encodeURIComponent(chapterId)}?selected_language=pt-br`;
    const json = await this.requestJson(url);
    const data = json && json.data ? json.data : {};
    const images = this.toArray(data.images);

    return images
      .filter((image) => image && image.default_url)
      .map((image, index) => ({
        url: image.default_url,
        index: index,
        headers: {},
      }));
  }

  getSettings() {
    return {
      supportsMultiLanguage: false,
      supportsMultiScanlator: false,
    };
  }
}
